prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?model
  ?modelName
  ?originalId
  ?created
  ?orgId
  ?choreoCount
WHERE {
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:originalId ?originalId ;
         tai:modelCreated ?created ;
         tai:belongsTo ?org .
  ?org tai:organizationId ?orgId .
  OPTIONAL {
    SELECT (COUNT(DISTINCT ?choreo) AS ?choreoCount) WHERE {
      ?choreo a bboExt:Choreography .
      ?choreo tai:belongsTo ?defs .
      ?defs tai:belongsTo ?model .
    }
  }
  FILTER(?originalId = "3c08e52742754da6a4065fc5787131dc" || ?modelName = "3c08e52742754da6a4065fc5787131dc")
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?choreo
  (COUNT(DISTINCT ?task) AS ?taskCount)
  (COUNT(DISTINCT ?start) AS ?startCount)
  (COUNT(DISTINCT ?end) AS ?endCount)
  (COUNT(DISTINCT ?gwXor) AS ?xorCount)
  (COUNT(DISTINCT ?gwAnd) AS ?andCount)
  (COUNT(DISTINCT ?gwEvent) AS ?eventGwCount)
  (COUNT(DISTINCT ?seqFlow) AS ?seqFlowCount)
  (COUNT(DISTINCT ?msgFlow) AS ?msgFlowCount)
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "3c08e52742754da6a4065fc5787131dc" .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  OPTIONAL { ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo . }
  OPTIONAL { ?start a bboExt:StartEvent ; tai:belongsTo ?choreo . }
  OPTIONAL { ?end a bboExt:EndEvent ; tai:belongsTo ?choreo . }
  OPTIONAL { ?gwXor a bboExt:ExclusiveGateway ; tai:belongsTo ?choreo . }
  OPTIONAL { ?gwAnd a bboExt:ParallelGateway ; tai:belongsTo ?choreo . }
  OPTIONAL { ?gwEvent a bboExt:EventBasedGateway ; tai:belongsTo ?choreo . }
  OPTIONAL { ?seqFlow a bbo:SequenceFlow ; tai:belongsTo ?choreo . }
  OPTIONAL { ?msgFlow a bboExt:MessageFlow ; tai:belongsTo ?choreo . }
}
GROUP BY ?choreo
ORDER BY DESC(?taskCount + ?seqFlowCount + ?msgFlowCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?choreo
  (COUNT(DISTINCT ?unnamed) AS ?unnamedElements)
  (COUNT(DISTINCT ?unnamedTask) AS ?unnamedTasks)
  (COUNT(DISTINCT ?unnamedGw) AS ?unnamedGateways)
  (COUNT(DISTINCT ?unnamedEvent) AS ?unnamedEvents)
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "3c08e52742754da6a4065fc5787131dc" .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?unnamed a ?t ;
           tai:belongsTo ?choreo ;
           bbo:name ?nm .
  FILTER(!BOUND(?nm) || STRLEN(STR(?nm)) = 0)

  OPTIONAL { ?unnamed a bboExt:ChoreographyTask .  BIND(?unnamed AS ?unnamedTask) }
  OPTIONAL { ?unnamed a bboExt:ExclusiveGateway . BIND(?unnamed AS ?unnamedGw) }
  OPTIONAL { ?unnamed a bboExt:ParallelGateway .  BIND(?unnamed AS ?unnamedGw) }
  OPTIONAL { ?unnamed a bboExt:EventBasedGateway . BIND(?unnamed AS ?unnamedGw) }
  OPTIONAL { ?unnamed a bboExt:StartEvent . BIND(?unnamed AS ?unnamedEvent) }
  OPTIONAL { ?unnamed a bboExt:IntermediateCatchEvent . BIND(?unnamed AS ?unnamedEvent) }
  OPTIONAL { ?unnamed a bboExt:EndEvent . BIND(?unnamed AS ?unnamedEvent) }
}
GROUP BY ?choreo
ORDER BY DESC(?unnamedElements)
LIMIT 10
